import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"37. Uniform And Protective Clothing","description":"","frontmatter":{"title":"37. Uniform And Protective Clothing","eba":"Biomedical Engineers 2025-2028","topics":["allowances","uniforms"]},"headers":[],"relativePath":"ebas/biomedical-engineers/allowances/37-uniform-and-protective-clothing.md","filePath":"ebas/biomedical-engineers/allowances/37-uniform-and-protective-clothing.md"}'),n={name:"ebas/biomedical-engineers/allowances/37-uniform-and-protective-clothing.md"};function i(s,e,l,p,h,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_37-uniform-and-protective-clothing" tabindex="-1">37. Uniform And Protective Clothing <a class="header-anchor" href="#_37-uniform-and-protective-clothing" aria-label="Permalink to &quot;37. Uniform And Protective Clothing&quot;">​</a></h1><p>For the purposes of this clause 37, uniform means such specific apparel as may be required by the Employer.</p><p><strong>37.1</strong> Where an Employer requires an Employee to wear a uniform the Employer must reimburse the Employee for the cost of purchasing such uniform, unless the uniform is paid for by the Employer.</p><p><strong>37.2</strong> Where an Employer provides an Employee with a uniform:</p><p><strong>(a)</strong> all articles so provided remain the property of the Employer, and</p><p><strong>(b)</strong> the Employer will replace uniforms where necessary on a fair ‘wear and tear’ basis.</p><p><strong>37.3</strong> Notwithstanding subclause 37.1, the Employer may, by agreement with the Employee, pay a uniform allowance at the daily or weekly rate set out in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> (whichever is the lesser amount in total) when the Employee is expected to provide their own uniform.</p><p><strong>37.4</strong> When such Employee’s uniform is not laundered by or at the expense of the Employer, the Employee will be paid a laundry allowance at the daily or weekly rate set out in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>, (whichever is the lesser amount in total).</p><p><strong>37.5</strong> The uniform allowance but not the laundry allowance will be paid during all absences on paid leave, except absence on long service leave, and absence on personal/carers leave beyond 21 days. Where, prior to taking leave, an Employee was paid a uniform allowance other than at the weekly rate, the rate to be paid during absence on leave will be the average of the allowance paid during the four weeks immediately preceding the taking of leave.</p><p><strong>37.6</strong> An Employer must not unreasonably refuse to allow an Employee to wear clothing suitable for a health setting (for example, scrubs), if the Employee does so at their own expense.</p><p><strong>37.7</strong> Damaged Clothing</p><p><strong>(a)</strong> Reasonable and necessary costs, as determined by the Employer, will be reimbursed in relation to an Employee’s clothing or other personal effects becoming damaged or soiled as a direct consequence of engaging in authorised duties.</p><p><strong>(b)</strong> Reasonable and necessary costs are those that relate to cleaning, repair or replacement of such clothing or other personal effects.</p><p><strong>(c)</strong> Employees may apply for reimbursement up to a maximum of $500 per calendar year where:</p><p><strong>(i)</strong> immediate notification of the damage to the clothing or other personal effects, arising from the Employee engaging in authorised duties, has been given, and</p><p><strong>(ii)</strong> evidence of the damage to the clothing has been sighted by the relevant authorising officer, and</p><p><strong>(iii)</strong> the Employee presents a valid receipt for costs incurred as a result of clothing or other personal effects requiring cleaning, repair or replacement, and</p><p><strong>(iv)</strong> the damage or soiling was not occasioned by the Employee’s negligence.</p><p><strong>37.8</strong> Protective Equipment</p><p><strong>(a)</strong> Employers and Employees are committed to the observance of safe working practices and the correct use of all personal protective equipment (PPE).</p><p><strong>(b)</strong> Employees required to wear PPE in the course of their duties, will be provided with appropriate guidance and instruction on the use of PPE.</p><p><strong>(c)</strong> The Employer will provide such gloves, masks, tunics, gowns and such PPE and safety appliances as are required for an Employee to properly and safely perform their work.</p><p><strong>37.9</strong> Laundering of Protective Clothing (however titled) Protective clothing (however titled) shall be laundered at the expense of the Employer.</p>',23)])])}const g=o(n,[["render",i]]);export{m as __pageData,g as default};
